INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('32e246ea-a03b-4a78-aafb-8afd0341ba2a', 'Sex ed in high school was pure terror. They showed us photos of diseases that looked like alien landscape photography. The message was clear: ''If you touch another human being, your body will rot.'' No wonder we''re all in therapy.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('f12d05c7-1cb7-46e4-ab67-94bc532ba07b', 'I saw a Tinder profile that said: ''Must be over 6 feet, make six figures, and have a good relationship with your mother.'' That''s not a dating profile; that''s a job posting for a guy who will eventually murder you for the insurance money.', '[standup] Seed', 100, 0);
INSERT INTO jokes (id, text, premise, kills, bombs) VALUES ('041a4062-3f48-4cd5-b823-7917f1f4a2d2', 'My friend told me she started an OnlyFans to pay off her student loans. Honestly, it''s the only honest business model left. You show your feet, you get paid. Compare that to corporate life, where you show your soul for 40 years and get a plastic pen when you retire.', '[standup] Seed', 100, 0);
